      nbf: 1,
      org_id: "fly-org-id",
      org_name: "example-org",
      sub: "example-org:fixture-app:fixture-machine",
    };

    expect(
      adapter.validateSubjectTokenBinding({
        claims,
        expectedAudience: "cyspbot",
        issuer: "https://oidc.fly.io/example-org",
      }),
    ).toBe(true);
    expect(
